package com.example.auth.mfa;

import com.example.auth.user.AppUser;
import com.example.auth.user.AppUserRepository;
import com.example.auth.user.BackupCode;
import com.example.auth.user.BackupCodeRepository;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;

@Service
public class BackupCodeService {
    private static final int DEFAULT_CODE_COUNT = 10;
    private static final int CODE_LENGTH = 10;
    private static final String ALPHABET = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";

    private final BackupCodeRepository backupCodeRepository;
    private final AppUserRepository appUserRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom = new SecureRandom();

    public BackupCodeService(BackupCodeRepository backupCodeRepository,
                             AppUserRepository appUserRepository,
                             PasswordEncoder passwordEncoder) {
        this.backupCodeRepository = backupCodeRepository;
        this.appUserRepository = appUserRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public List<String> generateAndStoreBackupCodes(AppUser user) {
        backupCodeRepository.deleteByUserId(user.getId());

        List<String> plainCodes = new ArrayList<>();
        for (int i = 0; i < DEFAULT_CODE_COUNT; i++) {
            String code = generateReadableCode();
            BackupCode backupCode = new BackupCode();
            backupCode.setUser(user);
            backupCode.setCodeHash(passwordEncoder.encode(code));
            backupCode.setUsed(false);
            backupCodeRepository.save(backupCode);
            plainCodes.add(code);
        }
        return plainCodes;
    }

    @Transactional
    public List<String> regenerateBackupCodes(String username) {
        AppUser user = appUserRepository.findByUsername(username)
                .orElseThrow(() -> new EntityNotFoundException("User not found"));
        if (!user.isMfaEnabled()) {
            throw new IllegalStateException("MFA must be enabled before generating backup codes");
        }
        return generateAndStoreBackupCodes(user);
    }

    @Transactional
    public boolean consumeBackupCode(String username, String rawCode) {
        AppUser user = appUserRepository.findByUsername(username)
                .orElseThrow(() -> new EntityNotFoundException("User not found"));

        if (!user.isMfaEnabled()) {
            return false;
        }

        List<BackupCode> activeCodes = backupCodeRepository.findByUserIdAndUsedFalse(user.getId());
        for (BackupCode backupCode : activeCodes) {
            if (passwordEncoder.matches(normalize(rawCode), backupCode.getCodeHash())) {
                backupCode.setUsed(true);
                backupCode.setUsedAt(Instant.now());
                backupCodeRepository.save(backupCode);
                return true;
            }
        }
        return false;
    }

    private String generateReadableCode() {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < CODE_LENGTH; i++) {
            if (i > 0 && i % 5 == 0) {
                sb.append('-');
            }
            sb.append(ALPHABET.charAt(secureRandom.nextInt(ALPHABET.length())));
        }
        return sb.toString();
    }

    private String normalize(String code) {
        return code == null ? "" : code.replace("-", "").replace(" ", "").toUpperCase();
    }
}

package com.example.auth.mfa;

import com.example.auth.mfa.dto.AuthenticationResponse;
import com.example.auth.mfa.dto.EnableMfaRequest;
import com.example.auth.mfa.dto.EnableMfaResponse;
import com.example.auth.user.AppUser;
import com.example.auth.user.AppUserRepository;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

@Service
public class MfaService {
    private final AppUserRepository appUserRepository;
    private final BackupCodeService backupCodeService;

    public MfaService(AppUserRepository appUserRepository, BackupCodeService backupCodeService) {
        this.appUserRepository = appUserRepository;
        this.backupCodeService = backupCodeService;
    }

    @Transactional
    public EnableMfaResponse enableMfa(EnableMfaRequest request) {
        AppUser user = appUserRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new EntityNotFoundException("User not found"));

        user.setMfaEnabled(true);
        user.setMfaSecret(request.getMfaSecret());
        appUserRepository.save(user);

        List<String> backupCodes = backupCodeService.generateAndStoreBackupCodes(user);
        return new EnableMfaResponse(user.getUsername(), true, backupCodes);
    }

    @Transactional(readOnly = true)
    public AuthenticationResponse authenticateWithBackupCode(String username, String backupCode) {
        boolean authenticated = backupCodeService.consumeBackupCode(username, backupCode);
        if (authenticated) {
            return new AuthenticationResponse(true, "Authenticated using backup code");
        }
        return new AuthenticationResponse(false, "Invalid or already used backup code");
    }
}

package com.example.auth.mfa;

import com.example.auth.mfa.dto.AuthenticationResponse;
import com.example.auth.mfa.dto.BackupCodeLoginRequest;
import com.example.auth.mfa.dto.EnableMfaRequest;
import com.example.auth.mfa.dto.EnableMfaResponse;
import com.example.auth.mfa.dto.RegenerateBackupCodesRequest;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/api/mfa")
public class MfaController {
    private final MfaService mfaService;
    private final BackupCodeService backupCodeService;

    public MfaController(MfaService mfaService, BackupCodeService backupCodeService) {
        this.mfaService = mfaService;
        this.backupCodeService = backupCodeService;
    }

    @PostMapping("/enable")
    public ResponseEntity<EnableMfaResponse> enableMfa(@Valid @RequestBody EnableMfaRequest request) {
        return ResponseEntity.ok(mfaService.enableMfa(request));
    }

    @PostMapping("/backup-code/authenticate")
    public ResponseEntity<AuthenticationResponse> authenticateWithBackupCode(@Valid @RequestBody BackupCodeLoginRequest request) {
        AuthenticationResponse response = mfaService.authenticateWithBackupCode(request.getUsername(), request.getBackupCode());
        return ResponseEntity.ok(response);
    }

    @PostMapping("/backup-codes/regenerate")
    public ResponseEntity<List<String>> regenerateBackupCodes(@Valid @RequestBody RegenerateBackupCodesRequest request) {
        return ResponseEntity.ok(backupCodeService.regenerateBackupCodes(request.getUsername()));
    }
}

